using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder = @"C:\uploads";

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            if (!File.Exists(filePath))
                return NotFound();

            var fileExtension = Path.GetExtension(filename).ToLower();
            switch (fileExtension)
            {
                case ".pdf":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/pdf");
                case ".docx", ".doc":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/vnd.openxmlformats-officedocument.wordprocessingml.document");
                case ".xlsx", ".xls":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
                case ".pptx", ".ppt":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/vnd.openxmlformats-officedocument.presentationml.presentation");
                default:
                    var mimeType = MimeMapping.GetMimeMapping(filename);
                    if (string.IsNullOrEmpty(mimeType))
                        mimeType = "application/octet-stream";
                    return File(System.IO.File.ReadAllBytes(filePath), mimeType);
            }
        }
    }
}